def main():
    def run():
        data = input()
        data = data.replace("x", "*").replace("/", "//")
        return eval(data)
    n = int(input())
    try:
        for _ in range(n):
            if run() == 24:
                print("Yes", end=" ")
            else:
                print("No", end=" ")
    except:
        print("ERROR")

main()
